	//	    target: { position: -1, role: 'user' }
	//	  }]
	//	}
	//
	// ```
	//
	// // Example 3: Reject transfer if user didn't mention transfer recently
	// ```json
	//
	//	{
	//	  conditions: [{
	//	    type: 'liquid',
