	//
	//	{% if msg.content contains 'transfer' or msg.content contains 'connect' or msg.content contains 'speak to' %}
	//	  {% assign mentioned = true %}
	//	  {% break %}
	//	{% endif %}
	//
	// {% endfor %}
	// {% if mentioned %}
	//
	//	false
	//
	// {% else %}
	//
